mapper.select:
SELECT mr.id as id , name as name, description as description, mu.nickname as creator, mr.create_time as createTime, status as status FROM md_role mr LEFT JOIN md_tenant_role mtr ON mtr.role_id = mr.id LEFT JOIN md_user mu ON mr.create_by = mu.id WHERE mr.app_id = #{appId} AND mtr.tenant_id = #{tenantId}
AND (mr.name like LOWER(concat('%',#{roleName},'%')) OR mr.name like UPPER(concat('%',#{roleName},'%')))
GROUP BY mr.id ORDER BY mr.create_time ASC
